// // This module compares two 8-bit numbers and outputs signals indicating if the first number is less than, greater than, or equal to the second number.
module magnitude_comparator (
    input [7:0] a,
    input [7:0] b,
    output reg gt,
    output reg lt,
    output reg eq
);always @* begin
    if (a > b) begin
        gt = 1;
        lt = 0;
        eq = 0;
    end else if (a < b) begin
        gt = 0;
        lt = 1;
        eq = 0;
    end else begin
        gt = 0;
        lt = 0;
        eq = 1;
    end
end

endmodule
